<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Orion Desktop</title>
<style>
  :root {
    --bg: #17151d;
    --panel: rgba(39, 35, 47, 0.96);
    --panel-light: #4a4459;
    --window: #292532;
    --window-content: #24212c;
    --accent: #e95420;
    --accent-light: #ff7544;
    --text: #f4f1f6;
    --muted: #b6afbf;
    --line: rgba(255,255,255,.12);
    --shadow: 0 18px 48px rgba(0,0,0,.48);
  }

  * { box-sizing: border-box; }

  html, body {
    margin: 0;
    width: 100%;
    height: 100%;
    overflow: hidden;
    font-family: Arial, Helvetica, sans-serif;
    color: var(--text);
  }

  button, textarea {
    font: inherit;
  }

  button {
    color: inherit;
  }

  #desktop {
    position: relative;
    width: 100vw;
    height: 100vh;
    min-height: 100vh;
    overflow: hidden;
    background:
      radial-gradient(circle at 76% 25%, rgba(234, 84, 32, .62) 0, rgba(234, 84, 32, .22) 18%, transparent 38%),
      radial-gradient(ellipse at 27% 83%, rgba(93, 54, 127, .78) 0, rgba(50, 31, 69, .37) 31%, transparent 56%),
      linear-gradient(135deg, #201426 0%, #35203c 43%, #1c1a2b 100%);
  }

  #desktop::before,
  #desktop::after {
    content: "";
    position: absolute;
    pointer-events: none;
    border-radius: 50%;
    filter: blur(2px);
    opacity: .35;
  }

  #desktop::before {
    width: 62vw;
    height: 62vw;
    top: 26%;
    left: -22%;
    border: 2px solid rgba(255,255,255,.08);
    box-shadow: 0 0 0 55px rgba(255,255,255,.025), 0 0 0 140px rgba(255,255,255,.018);
  }

  #desktop::after {
    width: 40vw;
    height: 40vw;
    right: -8%;
    bottom: -18%;
    background: rgba(255, 128, 67, .14);
  }

  #topbar {
    position: absolute;
    z-index: 20;
    top: 0;
    left: 0;
    right: 0;
    height: 34px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    background: rgba(22, 20, 28, .88);
    border-bottom: 1px solid rgba(255,255,255,.08);
    font-size: 13px;
    backdrop-filter: blur(10px);
  }

  .top-brand {
    display: flex;
    gap: 8px;
    align-items: center;
    font-weight: bold;
  }

  .top-dot {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background: var(--accent);
    box-shadow: 0 0 0 3px rgba(233,84,32,.18);
  }

  .top-status {
    color: var(--muted);
    font-size: 12px;
  }

  .desktop-label {
    position: absolute;
    z-index: 1;
    top: 62px;
    left: 28px;
    width: 88px;
    text-align: center;
    color: white;
    font-size: 13px;
    text-shadow: 0 2px 4px #000;
  }

  .desktop-icon {
    display: grid;
    place-items: center;
    width: 58px;
    height: 50px;
    margin: 0 auto 5px;
    font-size: 39px;
    color: #ffce77;
  }

  #taskbar {
    position: absolute;
    z-index: 50;
    left: 50%;
    bottom: 17px;
    transform: translateX(-50%);
    display: flex;
    gap: 10px;
    align-items: center;
    padding: 9px 12px;
    border: 1px solid rgba(255,255,255,.15);
    border-radius: 18px;
    background: rgba(29, 25, 36, .86);
    box-shadow: 0 10px 30px rgba(0,0,0,.38);
    backdrop-filter: blur(14px);
  }

  .launcher {
    min-width: 72px;
    border: 0;
    border-radius: 11px;
    padding: 7px 10px;
    background: transparent;
    cursor: pointer;
    transition: background .16s ease, transform .16s ease;
  }

  .launcher:hover,
  .launcher:focus-visible {
    background: rgba(255,255,255,.13);
    outline: none;
    transform: translateY(-2px);
  }

  .launcher-icon {
    display: block;
    height: 29px;
    font-size: 26px;
    line-height: 29px;
  }

  .launcher-name {
    display: block;
    margin-top: 4px;
    font-size: 11px;
    color: #e7e1eb;
  }

  .window {
    position: absolute;
    z-index: 10;
    display: none;
    flex-direction: column;
    width: 680px;
    height: 470px;
    min-width: 360px;
    min-height: 240px;
    overflow: hidden;
    border: 1px solid rgba(255,255,255,.18);
    border-radius: 12px;
    background: var(--window);
    box-shadow: var(--shadow);
  }

  .window.visible {
    display: flex;
  }

  #files-window {
    top: 70px;
    left: max(40px, calc(50% - 395px));
  }

  #notepad-window {
    top: 112px;
    left: max(70px, calc(50% - 120px));
    width: 650px;
    height: 455px;
  }

  .window.active {
    box-shadow: 0 20px 58px rgba(0,0,0,.64), 0 0 0 1px rgba(233,84,32,.32);
  }

  .titlebar {
    height: 42px;
    flex: 0 0 42px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 9px 0 14px;
    background: linear-gradient(#3b3547, #322d3c);
    border-bottom: 1px solid var(--line);
    cursor: grab;
    user-select: none;
  }

  .titlebar:active {
    cursor: grabbing;
  }

  .window-title {
    display: flex;
    align-items: center;
    gap: 9px;
    font-size: 14px;
    font-weight: bold;
  }

  .window-title-icon {
    color: var(--accent-light);
    font-size: 18px;
  }

  .window-controls {
    display: flex;
    gap: 5px;
  }

  .win-close {
    width: 27px;
    height: 27px;
    border: 0;
    border-radius: 7px;
    background: transparent;
    color: #f8eef0;
    font-size: 20px;
    line-height: 24px;
    cursor: pointer;
  }

  .win-close:hover,
  .win-close:focus-visible {
    background: #d63b32;
    outline: none;
  }

  .files-toolbar {
    flex: 0 0 49px;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 8px 13px;
    background: #302b39;
    border-bottom: 1px solid var(--line);
  }

  #files-up {
    width: 34px;
    height: 31px;
    border: 0;
    border-radius: 7px;
    background: #454052;
    color: white;
    cursor: pointer;
    font-size: 20px;
  }

  #files-up:hover:not(:disabled) {
    background: var(--accent);
  }

  #files-up:disabled {
    opacity: .4;
    cursor: default;
  }

  #files-path {
    flex: 1;
    min-width: 0;
    padding: 8px 11px;
    border-radius: 6px;
    background: #201d27;
    border: 1px solid rgba(255,255,255,.09);
    color: #eeeaf0;
    font-family: monospace;
    font-size: 14px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  #files-list {
    flex: 1;
    min-height: 0;
    display: grid;
    align-content: start;
    grid-template-columns: repeat(auto-fill, minmax(130px, 1fr));
    gap: 10px;
    padding: 17px;
    overflow: auto;
    background: var(--window-content);
  }

  .fs-item {
    min-height: 88px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 7px;
    padding: 9px 6px;
    border: 1px solid transparent;
    border-radius: 8px;
    color: #f2eff4;
    cursor: default;
    text-align: center;
    overflow-wrap: anywhere;
    font-size: 13px;
  }

  .fs-item:hover,
  .fs-item.selected {
    background: rgba(233,84,32,.18);
    border-color: rgba(255,143,99,.4);
  }

  .fs-symbol {
    font-size: 34px;
    line-height: 34px;
  }

  .fs-item.file .fs-symbol {
    color: #aab9df;
  }

  .empty-folder {
    grid-column: 1 / -1;
    color: var(--muted);
    padding: 28px;
    text-align: center;
  }

  .notepad-body {
    flex: 1;
    min-height: 0;
    display: flex;
    flex-direction: column;
    background: #201d27;
  }

  .tab-row {
    flex: 0 0 43px;
    display: flex;
    align-items: stretch;
    gap: 2px;
    padding: 6px 7px 0;
    overflow-x: auto;
    background: #302b39;
    border-bottom: 1px solid var(--line);
  }

  #tabs {
    display: flex;
    min-width: 0;
    gap: 3px;
    overflow-x: auto;
  }

  .tab {
    min-width: 118px;
    max-width: 180px;
    padding: 0 13px;
    border: 1px solid transparent;
    border-radius: 7px 7px 0 0;
    background: #403a4c;
    color: #d1cad7;
    cursor: pointer;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    font-size: 13px;
  }

  .tab:hover {
    background: #4a4356;
  }

  .tab.active {
    background: #25212d;
    border-color: rgba(255,255,255,.1);
    border-bottom-color: #25212d;
    color: white;
  }

  #new-tab {
    flex: 0 0 34px;
    width: 34px;
    margin-left: 5px;
    border: 0;
    border-radius: 7px 7px 0 0;
    background: transparent;
    color: #f1edf4;
    font-size: 23px;
    cursor: pointer;
  }

  #new-tab:hover,
  #new-tab:focus-visible {
    background: rgba(255,255,255,.12);
    outline: none;
  }

  #editor {
    flex: 1;
    width: 100%;
    min-height: 0;
    resize: none;
    border: 0;
    outline: none;
    padding: 17px 19px;
    background: #25212d;
    color: #f2eff4;
    font-family: "Courier New", monospace;
    font-size: 14px;
    line-height: 1.55;
    tab-size: 4;
  }

  .editor-status {
    flex: 0 0 27px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0 12px;
    background: #302b39;
    color: var(--muted);
    font-size: 11px;
    border-top: 1px solid var(--line);
  }

  @media (max-width: 720px) {
    #files-window, #notepad-window {
      left: 8px;
      width: calc(100vw - 16px);
    }

    #files-window { top: 48px; }
    #notepad-window { top: 76px; }

    .top-status { display: none; }
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <div class="top-brand"><span class="top-dot"></span>Orion Desktop</div>
    <div class="top-status">Activities &nbsp; • &nbsp; Workspace 1</div>
  </div>

  <div class="desktop-label" aria-hidden="true">
    <div class="desktop-icon">⌂</div>
    Home
  </div>

  <section id="files-window" class="window" aria-label="Files window">
    <div class="titlebar">
      <div class="window-title"><span class="window-title-icon">▣</span>Files</div>
      <div class="window-controls">
        <button class="win-close" aria-label="Close Files window" title="Close">×</button>
      </div>
    </div>
    <div class="files-toolbar">
      <button id="files-up" aria-label="Go to parent folder" title="Parent folder">↑</button>
      <div id="files-path" aria-label="Current file path">/</div>
    </div>
    <div id="files-list" aria-label="File listing"></div>
  </section>

  <section id="notepad-window" class="window" aria-label="Notepad window">
    <div class="titlebar">
      <div class="window-title"><span class="window-title-icon">▤</span>Notepad</div>
      <div class="window-controls">
        <button class="win-close" aria-label="Close Notepad window" title="Close">×</button>
      </div>
    </div>
    <div class="notepad-body">
      <div class="tab-row">
        <div id="tabs" aria-label="Notepad tabs"></div>
        <button id="new-tab" aria-label="Create new tab" title="New tab">+</button>
      </div>
      <textarea id="editor" aria-label="Text editor" spellcheck="false" placeholder="Start writing..."></textarea>
      <div class="editor-status"><span>Plain Text</span><span id="save-status">Saved locally</span></div>
    </div>
  </section>

  <nav id="taskbar" aria-label="Application dock">
    <button id="open-files" class="launcher" aria-label="Open Files">
      <span class="launcher-icon">▣</span>
      <span class="launcher-name">Files</span>
    </button>
    <button id="open-notepad" class="launcher" aria-label="Open Notepad">
      <span class="launcher-icon">▤</span>
      <span class="launcher-name">Notepad</span>
    </button>
  </nav>
</div>

<script>
(function () {
  "use strict";

  const filesWindow = document.getElementById("files-window");
  const notepadWindow = document.getElementById("notepad-window");
  const openFiles = document.getElementById("open-files");
  const openNotepad = document.getElementById("open-notepad");
  let highestZ = 10;

  function showWindow(win) {
    win.classList.add("visible");
    highestZ += 1;
    win.style.zIndex = highestZ;
    document.querySelectorAll(".window").forEach(w => w.classList.remove("active"));
    win.classList.add("active");
  }

  function hideWindow(win) {
    win.classList.remove("visible", "active");
  }

  openFiles.addEventListener("click", () => showWindow(filesWindow));
  openNotepad.addEventListener("click", () => {
    showWindow(notepadWindow);
    setTimeout(() => editor.focus(), 0);
  });

  document.querySelectorAll(".win-close").forEach(button => {
    button.addEventListener("click", function (event) {
      event.stopPropagation();
      hideWindow(this.closest(".window"));
    });
  });

  document.querySelectorAll(".window").forEach(win => {
    win.addEventListener("mousedown", () => {
      if (win.classList.contains("visible")) showWindow(win);
    });
  });

  /* Draggable window title bars */
  document.querySelectorAll(".window").forEach(win => {
    const bar = win.querySelector(".titlebar");
    let dragging = false;
    let offsetX = 0;
    let offsetY = 0;

    bar.addEventListener("mousedown", event => {
      if (event.target.closest("button")) return;
      dragging = true;
      showWindow(win);
      const rect = win.getBoundingClientRect();
      offsetX = event.clientX - rect.left;
      offsetY = event.clientY - rect.top;
      event.preventDefault();
    });

    document.addEventListener("mousemove", event => {
      if (!dragging) return;
      const maxX = Math.max(0, window.innerWidth - 80);
      const maxY = Math.max(34, window.innerHeight - 70);
      const x = Math.min(maxX, Math.max(-win.offsetWidth + 80, event.clientX - offsetX));
      const y = Math.min(maxY, Math.max(34, event.clientY - offsetY));
      win.style.left = x + "px";
      win.style.top = y + "px";
    });

    document.addEventListener("mouseup", () => { dragging = false; });
  });

  /* Static fake Linux filesystem */
  const filesystem = {
    "/": [
      { name: "bin", type: "folder" },
      { name: "etc", type: "folder" },
      { name: "home", type: "folder" },
      { name: "usr", type: "folder" },
      { name: "var", type: "folder" },
      { name: "README.txt", type: "file" }
    ],
    "/bin": [
      { name: "bash", type: "file" },
      { name: "ls", type: "file" },
      { name: "python", type: "file" }
    ],
    "/etc": [
      { name: "hostname", type: "file" },
      { name: "network", type: "folder" },
      { name: "os-release", type: "file" }
    ],
    "/etc/network": [
      { name: "interfaces", type: "file" }
    ],
    "/home": [
      { name: "user", type: "folder" }
    ],
    "/home/user": [
      { name: "Documents", type: "folder" },
      { name: "Downloads", type: "folder" },
      { name: "Pictures", type: "folder" },
      { name: "welcome.txt", type: "file" },
      { name: "todo.md", type: "file" }
    ],
    "/home/user/Documents": [
      { name: "Projects", type: "folder" },
      { name: "notes.txt", type: "file" },
      { name: "report.pdf", type: "file" }
    ],
    "/home/user/Documents/Projects": [
      { name: "orion-desktop", type: "folder" }
    ],
    "/home/user/Documents/Projects/orion-desktop": [
      { name: "app.html", type: "file" }
    ],
    "/home/user/Downloads": [
      { name: "ubuntu-wallpaper.png", type: "file" },
      { name: "archive.zip", type: "file" }
    ],
    "/home/user/Pictures": [
      { name: "Sunset.jpg", type: "file" },
      { name: "Mountains.png", type: "file" }
    ],
    "/usr": [
      { name: "bin", type: "folder" },
      { name: "share", type: "folder" }
    ],
    "/usr/bin": [
      { name: "nano", type: "file" },
      { name: "node", type: "file" }
    ],
    "/usr/share": [
      { name: "applications", type: "folder" }
    ],
    "/var": [
      { name: "log", type: "folder" },
      { name: "tmp", type: "folder" }
    ],
    "/var/log": [
      { name: "system.log", type: "file" }
    ],
    "/var/tmp": []
  };

  let currentPath = "/";
  const filesPath = document.getElementById("files-path");
  const filesList = document.getElementById("files-list");
  const filesUp = document.getElementById("files-up");

  function joinPath(base, name) {
    return base === "/" ? "/" + name : base + "/" + name;
  }

  function parentPath(path) {
    if (path === "/") return "/";
    const parts = path.split("/").filter(Boolean);
    parts.pop();
    return parts.length ? "/" + parts.join("/") : "/";
  }

  function renderFiles() {
    filesPath.textContent = currentPath;
    filesUp.disabled = currentPath === "/";
    filesList.innerHTML = "";
    const entries = filesystem[currentPath] || [];

    if (!entries.length) {
      const empty = document.createElement("div");
      empty.className = "empty-folder";
      empty.textContent = "This folder is empty.";
      filesList.appendChild(empty);
      return;
    }

    entries.forEach(entry => {
      const item = document.createElement("div");
      item.className = "fs-item " + entry.type;
      item.tabIndex = 0;
      item.setAttribute("role", "button");
      item.setAttribute("aria-label", entry.name + (entry.type === "folder" ? ", folder" : ", file"));

      const symbol = document.createElement("span");
      symbol.className = "fs-symbol";
      symbol.textContent = entry.type === "folder" ? "📁" : "▧";

      const name = document.createElement("span");
      name.textContent = entry.name;

      item.append(symbol, name);
      item.addEventListener("click", () => {
        filesList.querySelectorAll(".fs-item").forEach(el => el.classList.remove("selected"));
        item.classList.add("selected");
      });

      if (entry.type === "folder") {
        const openFolder = () => {
          const next = joinPath(currentPath, entry.name);
          if (filesystem[next]) {
            currentPath = next;
            renderFiles();
          }
        };
        item.addEventListener("dblclick", openFolder);
        item.addEventListener("keydown", event => {
          if (event.key === "Enter") openFolder();
        });
      }

      filesList.appendChild(item);
    });
  }

  filesUp.addEventListener("click", () => {
    if (currentPath !== "/") {
      currentPath = parentPath(currentPath);
      renderFiles();
    }
  });

  renderFiles();

  /* Persistent tabbed notepad */
  const STORAGE_KEY = "orion-desktop-notepad-tabs-v1";
  const tabsElement = document.getElementById("tabs");
  const newTab = document.getElementById("new-tab");
  const editor = document.getElementById("editor");
  const saveStatus = document.getElementById("save-status");

  let noteState = {
    activeId: null,
    tabs: []
  };

  function makeId() {
    return "tab-" + Date.now() + "-" + Math.random().toString(36).slice(2, 8);
  }

  function defaultState() {
    const id = makeId();
    return {
      activeId: id,
      tabs: [{
        id: id,
        title: "Welcome",
        content: "Welcome to Orion Notepad.\n\nYour notes are saved automatically in this browser."
      }]
    };
  }

  function loadNotes() {
    try {
      const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
      if (saved && Array.isArray(saved.tabs) && saved.tabs.length) {
        noteState.tabs = saved.tabs.filter(tab =>
          tab && typeof tab.id === "string" && typeof tab.content === "string"
        ).map((tab, index) => ({
          id: tab.id,
          title: typeof tab.title === "string" ? tab.title : "Untitled " + (index + 1),
          content: tab.content
        }));
        if (noteState.tabs.length) {
          noteState.activeId = noteState.tabs.some(tab => tab.id === saved.activeId)
            ? saved.activeId
            : noteState.tabs[0].id;
          return;
        }
      }
    } catch (error) {
      /* Invalid unavailable storage falls back safely. */
    }
    noteState = defaultState();
    saveNotes();
  }

  function saveNotes() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(noteState));
      saveStatus.textContent = "Saved locally";
    } catch (error) {
      saveStatus.textContent = "Storage unavailable";
    }
  }

  function activeTab() {
    return noteState.tabs.find(tab => tab.id === noteState.activeId) || noteState.tabs[0];
  }

  function renderTabs() {
    const active = activeTab();
    if (!active) return;
    noteState.activeId = active.id;
    tabsElement.innerHTML = "";

    noteState.tabs.forEach(tab => {
      const button = document.createElement("button");
      button.className = "tab" + (tab.id === noteState.activeId ? " active" : "");
      button.textContent = tab.title;
      button.title = tab.title;
      button.setAttribute("aria-label", "Open tab " + tab.title);
      button.addEventListener("click", () => {
        noteState.activeId = tab.id;
        renderTabs();
        saveNotes();
        editor.focus();
      });
      tabsElement.appendChild(button);
    });

    editor.value = active.content;
  }

  newTab.addEventListener("click", () => {
    const id = makeId();
    const count = noteState.tabs.length + 1;
    noteState.tabs.push({
      id: id,
      title: "Untitled " + count,
      content: ""
    });
    noteState.activeId = id;
    renderTabs();
    saveNotes();
    editor.focus();
  });

  editor.addEventListener("input", () => {
    const tab = activeTab();
    if (!tab) return;
    tab.content = editor.value;
    saveStatus.textContent = "Saving...";
    saveNotes();
  });

  loadNotes();
  renderTabs();
})();
</script>
</body>
</html>
